var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그림자 전당으로 가신다고요?","JPN":"影の殿堂へ行くのですか？","ENG":"You're heading to the Shadow Palace?","TWN":"要去暗影殿堂？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"로터스의 대균열이 가장 안전한 진입루트라곤 하지만 고심도는 고심도입니다. 그림자 전당은 이웃집이 아녜요.","JPN":"ロータスの大亀裂が一番安全な進入ルートといっても、高深度には変わりません。影の殿堂は気軽に行ける場所ではないのです。","ENG":"Although Lotus' Grand Dimension Crevice is the safest route there, the hyperdepth is still the hyperdepth. The Shadow Palace isn't your next-door neighbor's house.","TWN":"洛德斯的大峽谷雖然是最安全的路線，但畢竟也是高深度地帶。暗影殿堂沒那麼容易出入。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"지난 번에도 몇 번씩이나 목숨이 위험하셨을 텐데요? 차라리 제가 갈 테니 기다리시죠.","JPN":"この前も命が危なかった瞬間が何度もありましたよね？私が行きますから、待っていてください。","ENG":"Even last time, you almost died a few times. I'll go instead, so wait for me.","TWN":"你過去也不是冒過幾次生命危險嗎？為什麼不等我過去呢？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아스널 윙 없이는 제때 도착하기 힘들 걸세. 자네는 아직 클리포트 게임의 뒷수습도 마무리 짓지 못한 상태잖나.","JPN":"アーセナルウイングがなければ間に合わないだろう。君はまだクリフォトゲームの後始末も残っているのではないか？","ENG":"It'll be hard to arrive on time without your Arsenal Wings. Plus, you're still caught up with cleaning up the mess from the Qliphoth Game.","TWN":"沒有軍火之翼，你很難及時趕到。而且你還沒有處理完逆卡巴拉遊戲的善後。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L7_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그리고, 적어도 난 도플갱어를 만날 일이 없으니 한시름 던 셈이지.","JPN":"それに、少なくとも私はドッペルゲンガーに会う可能性がないから、心配しなくてもいい。","ENG":"Also, it's better I go because I won't have to meet my doppelganger, at least.","TWN":"而且，我至少不用擔心遇到二重身。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"방금 그걸 농담이라고 하신 건가요?","JPN":"今のは冗談のつもりですか？","ENG":"Is that supposed to be a joke?","TWN":"你剛才是在開玩笑嗎？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"미안하게 됐군. 자네들이 어렵게 돌려받은 평화인데, 그리 오래가진 못하겠어.","JPN":"申し訳ない。君たちが頑張って取り戻した平和なのに、そう長くは持たなそうだ。","ENG":"You guys fought so hard to get back peace, and I'm sorry it didn't last long.","TWN":"抱歉，你們辛苦找回的和平馬上就要被瓦解了。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"미나 양은… 별말 없이 동행하겠다고 하던가요?","JPN":"ミナさんは……何も言わずに同行すると言ったのですか？","ENG":"Is Mina... accompanying you without saying anything?","TWN":"米娜她……二話不說就要和你同行？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래, 나를 위한 결정은 아니지만 지금은 함께 해주는 걸로도 고마운 일이지.","JPN":"そう、私のためではないが、今は一緒にいるだけでもありがたい。","ENG":"Yes. Although she's not doing it for me, I'm grateful to have her by my side.","TWN":"是的，雖然她這麼做並不是為了我，但我還是很感激能有她的陪伴。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"…말씀하신 대로, 그림자 전당 최심부까지 향하는 최단거리 좌표를 전송해드렸습니다.","JPN":"……おっしゃったとおりに、影の殿堂の最深部まで行く最短距離の座標を転送いたしました。","ENG":"...As you requested, I've sent you the coordinates for the shortest route to the deepest part of the Shadow Palace.","TWN":"……按你的吩咐，我已經把通往暗影殿堂最深處的最短距離座標發給你了。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이 정도면 민간 비행선도 그림자 전당까지 무사히 진입할 순 있겠죠.","JPN":"このくらいなら民間の飛行船でも影の殿堂まで無事に侵入できるでしょう。","ENG":"I believe even a commercial aircraft can reach the Shadow Palace safely.","TWN":"這麼一來，乘坐民用飛船也應該足以安全進入暗影殿堂。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"어디까지나 진입한 뒤가 문제지만요.","JPN":"進入した後が問題ですが。","ENG":"But the problem is after arriving there, I suppose.","TWN":"唯一的問題是在到達之後。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"고맙군, 부사장.","JPN":"ありがとう、副社長。","ENG":"Thank you, Vice President.","TWN":"謝謝你，副總。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"하지만 조심하세요.","JPN":"でも、気を付けてください。","ENG":"But be careful.","TWN":"但要小心。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그자가 방주를 건드렸다면 그곳의 보안 시스템도 정상은 아닐 겁니다.","JPN":"あの者が箱舟に触れたのなら、きっとセキュリティーシステムも正常ではないはずです。","ENG":"If she has already tampered with the Ark, the security system over there won't be normal.","TWN":"如果她動了方舟，那裡的安全系統可能也已經失常了。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>로터스 대균열 고심도, 그림자 전당. 코핀-6. 클리파 에너지 미량 유출 감지.</color>","JPN":"<color=#ffd34c>ロータスの大亀裂、高深度、影の殿堂。コフィン-6。微量のクリファエネルギーの流出を感知。</color>","ENG":"<color=#ffd34c>Lotus Grand Dimension Crevice Hyperdepths, Shadow Palace. Coffin-6. Small traces of Qlipha energy detected.</color>","TWN":"<color=#ffd34c>洛德斯大峽谷高深度，暗影殿堂。科芬-6.發現微量的逆卡巴拉能量洩漏痕跡。</color>"},"stage":{"bg":"black","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"갑자기 엄청 조용해졌네요. 함선에서 들려오던 경보음도 이젠 잠잠해졌고요.","JPN":"いきなり静かになりましたね。艦船から聞こえていた警報の音も止みましたし。","ENG":"It's suddenly so quiet. The alarms from the ship have also gone silent.","TWN":"突然變得非常安靜，艦船上的警報器也悄無聲息。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"여기서부턴 침식체가 하나도 안 보여요. 선배님이 너무 강하니까 도망쳤나봐요.","JPN":"ここからは侵食体が一体も見えません。先輩が強すぎるからみんな逃げたんじゃないんですか？","ENG":"I don't see any C.O.s from here on either. Maybe they ran away, seeing how strong Mina is.","TWN":"從這開始見不到任何侵蝕體，他們一定是因為前輩太強大而逃走了。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그렇게 방심하지 마. 스완은 이미 머릴 쓰는 침식체를 부린 전적이 있으니까.","JPN":"油断するな。スワンは頭を使う侵食体を操ったこともあるんだ。","ENG":"Don't let your guard down. Swan has already manipulated a thinking C.O. once.","TWN":"不要鬆懈。別忘了史旺曾經操縱過有智慧的侵蝕體。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L33_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"우리가 조심해야 할 건 침식체 뿐만이 아니라네.","JPN":"私たちが気を付けなければいけないのは侵食体だけではない。","ENG":"There are more than C.O.s to be cautious about.","TWN":"我們需要注意的不僅僅是侵蝕體。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"가령 하늘에서 떨어지는 입자광선이라거나…","JPN":"例えば空から降ってくる粒子の光線とか……","ENG":"For instance, a light beam that falls from the sky–","TWN":"例如一束從天而降的粒子光線……"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"……!","JPN":"……！","ENG":"...!","TWN":"……!"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"다들, 제 뒤로!","JPN":"みんな、私の後ろに！","ENG":"Everyone, get behind me!","TWN":"躲到我身後！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"흐아아, 한 발짝만 늦었어도 큰일날 뻔했다아.","JPN":"ふわああ、一歩でも遅れてたら大変なとこでしたぁ。","ENG":"Hyaagh, that was a close call.","TWN":"啊啊啊，晚一步就完蛋了。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"방금 뭐였죠? 광선? 침식체가 그런 것도 쏘나요?!","JPN":"今の何ですか？　光線？　侵食体にそんなことができるのですか！？","ENG":"What was that? A light beam? Did a C.O. shoot that?!","TWN":"剛剛那是什麼？射線嗎？侵蝕體會發射那種東西嗎？！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"이건 침식체 짓이 아니야.","JPN":"これは侵食体ではない。","ENG":"It's not a C.O.'s doing.","TWN":"那不是侵蝕體幹的。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"관리국 요격 병기의 입자포일세. 우릴 침입자로 간주하고 포격을 가한 거야.","JPN":"管理局の迎撃兵器からの粒子砲だ。私たちを侵入者と思って撃ったんだろう。","ENG":"It's the Administration's particle gun. It shot at us, thinking we were intruders.","TWN":"這是管理局攔擊武器的粒子砲。它把我們當成入侵者了。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"네?! 관리국 로봇이 왜 저흴 노리는 거죠?!","JPN":"はい！？　管理局のロボットが何で私たちを狙うんです！？","ENG":"Huh?! Why would the Administration robot have us in its sight?!","TWN":"什麼？為什麼管理局的機器人在攻擊我們？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"저것들을 컨트롤하려면 특별한 권한이 필요하지만…","JPN":"あれをコントロールするためには特別な権限が必要だが……","ENG":"One needs a special clearance level to be able to control those, and...","TWN":"控制它們本來需要特殊權限，但……"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"스완은 그 보안 시스템의 장악에 성공한 모양이군.","JPN":"スワンはそのセキュリティーシステムを掌握したようだな。","ENG":"it seems that Swan was successful in taking over the security system.","TWN":"史旺似乎已經掌握了它的安全系統。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};